function toLowerCase(s) {
    let result = '';
    for (let i = 0; i < s.length; i++) {
        let charCode = s.charCodeAt(i);
        if (charCode >= 65 && charCode <= 90) {
            charCode += 32;
        }
        result += String.fromCharCode(charCode);
    }
    return result;
}
```

